VALUES
  ('elementary-8b44517b-moex-00017', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-b3f42868', 'sub-elementary-8b44517b-01', NULL, 'single_choice', '總統制國家講求權力分立，下列何者不是此一體制下行政權與立法權互相制衡之設計？', '["覆議否決權", "人事同意權", "彈劾權", "罷免權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00018', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-b3f42868', 'sub-elementary-8b44517b-01', NULL, 'single_choice', '根據我國地方制度法之規定，下列那一個地方層級與其他三者不同？', '["嘉義市", "基隆市", "彰化市", "花蓮縣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00019', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-b3f42868', 'sub-elementary-8b44517b-01', NULL, 'single_choice', '有研究指出，西發利亞條約簽訂以後，主權國家逐漸生成，並逐漸形成當代以民族國家為中心的運作與國 際關係的基礎。以中央集權的主權國家為例，其特徵包括國家能穩定地收稅、進行集權式的管理、國家能 壟斷軍事，並能建立法治、外交與國族認同等。下列敘述何者正確？', '["中央集權的國家只會有單一國族認同", "實施聯邦制的國家不是主權國家", "西發利亞條約的簽訂對當代主權國家的生成有關鍵的影響", "西發利亞條約簽訂後，帝國就不再有跟主權國家抗衡的實力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00020', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-b3f42868', 'sub-elementary-8b44517b-01', NULL, 'single_choice', '針對選舉制度中弱勢群體保障名額的議題，有兩種不同的看法：一種主張在許多民主國家，女性國會議員 的比例已經接近 50%，因此應該改採「性少數保障名額」制度，因為性少數在參政上已經比婦女更加弱 勢。另一種主張在許多國家，即使女性國會議員比例高，但女性擔任部會首長的比例還是很低，因此「婦 女保障名額」制度仍需持續推行。上述關於弱勢群體保障名額的議題，最接近下列何種正義類型？', '["分配正義", "程序正義", "匡正正義", "轉型正義"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00021', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-b3f42868', 'sub-elementary-8b44517b-01', NULL, 'single_choice', '為避免酒駕憾事再度發生，2022年1月立法院三讀通過《中華民國刑法》，其中第185條之3之刑度， 由「2 年以下有期徒刑、得併科 20 萬元以下罰金」提升為「3 年以下有期徒刑、得併科 30 萬元以下罰 金」；酒駕致重傷維持「1年以上、7年以下有期徒刑」刑期，但增訂「得併科100萬元以下罰金」規定。 請問下列敘述何者正確？', '["酒駕致重傷增訂之刑責規定，意指若罰金繳納後，便無需接受有期徒刑之懲處", "於立法程序之「二讀」階段，立法委員針對本次修法內容逐項深入討論之", "按法規內容可知，酒駕之懲處隸屬於「生命刑、自由刑、財產刑」之範疇", "就本次修法內容可知，增訂之刑責與「追徵、追繳或抵償」皆屬從刑之範疇"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00022', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-b3f42868', 'sub-elementary-8b44517b-01', NULL, 'single_choice', '某學者指出：「針對重大公共決策，民選政府可以不採納專家意見，但不應該忽略或扭曲專家意見。例如， 民主的發展中國家不引進已開發國家藥廠專家所開發的有效療法，民選政府可以以各種合理理由拒絕，並 向專家與社會大眾說明，但不應基於特定政治考量，向大眾傳播該療法無效的不實說法。」下列何者最符 合以上敘述的要旨？', '["民選政府制定公共政策不採納專家意見，不符合民主精神", "發展中國家政府採購已開發國家藥廠的藥品會延續殖民主義的剝削", "民選政府在公共決策過程中審慎考量專家意見有助於民主與治理", "民主國家中，不採納專家意見的政府就是民粹政府"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00023', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-b3f42868', 'sub-elementary-8b44517b-01', NULL, 'single_choice', '依據我國憲法規定及大法官解釋之意旨，關於政黨比例代表制，下列敘述何者正確？', '["憲法增修條文規定，獲得政黨選舉票百分之五以上之政黨，始得分配全國不分區立法委員席次，已違反 憲法上之平等原則", "公職人員選舉罷免法規定，依政黨得票總數比例方式產生之全國不分區立法委員當選人不適用罷免規 定，已違反憲法保障人民罷免權意旨", "憲法增修條文對立法委員之選舉採單一選區兩票制，是有意兼顧選區代表性與政黨多元性，未牴觸民主 共和國與國民主權原則", "依政黨得票總數比例方式產生之全國不分區立法委員，縱喪失其所屬政黨之黨員資格，仍不影響其作為 民意代表之資格"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00024', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-b3f42868', 'sub-elementary-8b44517b-01', NULL, 'single_choice', '下列關於權利主體之敘述，何者錯誤？', '["自然人的權利能力始於出生登記", "法人的權利能力始於登記成立", "自然人遭戶政機關除籍，也不影響該自然人的權利能力", "發起人於法人成立後脫離法人團體，也不影響該法人的權利能力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00025', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-b3f42868', 'sub-elementary-8b44517b-01', NULL, 'single_choice', '下列關於國際人權公約在我國實踐之敘述，何者錯誤？', '["我國並非聯合國會員國，故批准國際人權公約後無法存放於聯合國", "我國主動邀請國際人權專家至我國審查並提供觀察報告，以代替聯合國國家報告審查", "我國依憲法由立法院依條約案審議程序，主動將人權公約國內法化", "經過我國國內法化之國際人權公約，在規範效力上具有法律的位階"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00026', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-b3f42868', 'sub-elementary-8b44517b-01', NULL, 'single_choice', '關於法律的位階，下列何者錯誤？', '["特別法的位階高於普通法", "經立法院通過之國際條約位階等同法律", "法律的位階高於法規命令", "法規命令與憲法牴觸無效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:29+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL)
